/* ===== 训练内容增强函数 ===== */
function enrichModule(module){
  const training = MODULE_TRAINING[module.id];
  if(!training) return { ...module };
  return { ...module, training };
}

/* 全局导出 */
if(typeof window !== 'undefined'){
  window.MODULE_TRAINING = MODULE_TRAINING;
  window.enrichModule = enrichModule;
}